package com.example;

import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.method.annotation.RedirectMappedAnnotationHandlerMethodAdapter;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;

import org.springframework.stereotype.Controller;

@Controller
public class LogoutController {

    @GetMapping("/logout")
    public String logout(@RequestParam(value = "next", required = false) String next, HttpServletResponse response, HttpSession session) {
        session.invalidate();
        response.sendRedirect(next != null ? next : "/");
        return null;
    }
}